// Setup
Log.Logger = new LoggerConfiguration()
    .MinimumLevel.Information()
    .MinimumLevel.Override("Microsoft.EntityFrameworkCore", LogEventLevel.Warning)
    .Enrich.FromLogContext()
    .Enrich.WithProperty("Application", "MyApp")
    .WriteTo.Console(new JsonFormatter())
    .WriteTo.Seq("http://seq:5341")
    .CreateLogger();

builder.Host.UseSerilog();

// WRONG: string interpolation — luôn allocate dù tắt log
logger.LogInformation($"Order {order.Id} created for {customerId}");

// RIGHT: structured, queryable
logger.LogInformation(
    "Order {OrderId} created for customer {CustomerId} with total {Total:C}",
    order.Id, customerId, order.Total);

// Destructuring với '@'
logger.LogDebug("Processing {@Order}", order);

// Performance: IsEnabled check
if (logger.IsEnabled(LogLevel.Debug))
{
    var snapshot = ComputeExpensiveDebugInfo(); // chỉ gọi khi Debug on
    logger.LogDebug("Debug snapshot: {@Snapshot}", snapshot);
}

// LogContext — thêm prop cho mọi log trong scope
using (LogContext.PushProperty("RequestId", correlationId))
{
    // Mọi log trong using block có RequestId
}
